import React from 'react';

function HomePage() {
  // Step 6: Rendering Lists using .map()
  const blogPosts = [
    {
      id: 1,
      title: "The Brand Bloom",
      content: "I’ve fallen in love with capturing the bloom in every light...",
      img: "https://via.placeholder.com/350" // Replace with your image name later
    },
    {
      id: 2,
      title: "The Gardener of the Ceramic Soul",
      content: "I’ve discovered that my true passion isn't just growing my own petals...",
      img: "https://via.placeholder.com/350"
    },
    {
      id: 3,
      title: "Chasing the Horizon",
      content: "I want to be known as Cead—not just a name, but a mark of quality...",
      img: "https://via.placeholder.com/350"
    }
  ];

  return (
    <main>
      <section className="hero">
        <h1>The Brand Statement</h1>
        <p>My name is Edrick Mark, though I prefer to be called Cead...</p>
        <img src="https://via.placeholder.com/350" alt="Hero" /> {/* Fixed self-closing tag */}
      </section>

      <section className="preview-grid">
        {blogPosts.map((post) => (
          <div className="card" key={post.id}>
            <h3>{post.title}</h3>
            <p>{post.content}</p>
            <br /> {/* Fixed self-closing tag */}
            <img src={post.img} width="350" height="350" alt={post.title} />
          </div>
        ))}
      </section>
    </main>
  );
}

export default HomePage;
